[{"Patents_info": "Patent application (no. DE-102013211266-A) from DE, assigned to IBM, with publication number DE-102013211266-B4.", "kind_code": "B4", "application_kind": "A", "pct_number": "None", "family_id": "49754314", "title_localized": "[
