function.arguments:
{"code": "import json

# Load the Germany historical patent data
file_path = locals()['var_functions.query_db:24']

with open(file_path, 'r') as f:
    data = json.load(f)

print('Total Germany patent records loaded: ' + str(len(data)))

# Parse through records and extract CPC data with years
yearly_cpc_counts = {}
valid_records = 0

for record in data:
    grant_date = record.get('grant_date', '')
    patents_info = record.get('Patents_info', '')
    cpc = record.get('cpc', '[]')

    # Skip if not Germany patent
    if 'DE-' not in patents_info:
        continue

    # Extract year from grant_date
    year = None
    for y in range(2010, 2021):
        if str(y) in grant_date:
            year = y
            break

    if not year:
        continue

    valid_records += 1

    # Initialize year in dictionary if needed
    if year not in yearly_cpc_counts:
        yearly_cpc_counts[year] = {}

    # Parse CPC codes
    try:
        cpc_codes = json.loads(cpc)
    except:
        cpc_codes = []

    # Count CPC codes at level 4
    for cpc_entry in cpc_codes:
        code = cpc_entry.get('code', '')
        if not code:
            continue

        # Extract level 4 code (format: SectionClassSubclass/Group)
        # e.g., A61F5/01 from A61F5/0127
        parts = code.split('/')
        if len(parts) >= 2:
            main_class = parts[0]
            sub_class = parts[1]

            if len(sub_class) >= 2:
                level4_code = main_class + '/' + sub_class[:2]

                # Count it
                if level4_code in yearly_cpc_counts[year]:
                    yearly_cpc_counts[year][level4_code] += 1
                else:
                    yearly_cpc_counts[year][level4_code] = 1

print('Total valid records: ' + str(valid_records))
print('Years with data: ' + str(sorted(yearly_cpc_counts.keys())))

# Show sample data
sample_year = 2019
if sample_year in yearly_cpc_counts:
    codes_2019 = yearly_cpc_counts[sample_year]
    print('\nTop 10 CPC codes in 2019:')
    sorted_2019 = sorted(codes_2019.items(), key=lambda x: x[1], reverse=True)
    for code, count in sorted_2019[:10]:
        print('  ' + code + ': ' + str(count))

# Save the structured data
result = {
    'yearly_counts': yearly_cpc_counts,
    'total_records': valid_records
}

print('\n__RESULT__:')
print(json.dumps(result))"}

