{"code": "import json

# Load H2 2019 Germany patents
file_path = locals()['var_functions.query_db:32']
with open(file_path, 'r') as f:
    data = json.load(f)

print('Total H2 2019 patents: ' + str(len(data)))

# Extract CPC level 4 codes
cpc_counts_h2_2019 = {}
cpc_full_map = {}

for record in data:
    cpc_json = record.get('cpc', '[]')
    try:
        cpc_codes = json.loads(cpc_json)
    except:
        cpc_codes = []

    for entry in cpc_codes:
        code = entry.get('code', '')
        if not code:
            continue

        # Extract level 4
        parts = code.split('/')
        if len(parts) >= 2:
            main = parts[0]
            subgroup = parts[1]
            if len(subgroup) >= 2:
                level4 = main + '/' + subgroup[:2]
                cpc_counts_h2_2019[level4] = cpc_counts_h2_2019.get(level4, 0) + 1
                if level4 not in cpc_full_map:
                    cpc_full_map[level4] = code

# Get top 20 CPC codes by count in H2 2019
top_20 = sorted(cpc_counts_h2_2019.items(), key=lambda x: x[1], reverse=True)[:20]
print('\nTop 20 CPC level 4 codes in H2 2019:')
for code, count in top_20:
    print('  ' + code + ': ' + str(count))

result = {
    'top_codes': [code for code, _ in top_20],
    'full_map': cpc_full_map
}

print('\n__RESULT__:')
print(json.dumps(result))"}

